"""
MKT Christ Commentary — Hebrews chapters 10–11
Run: python3 scripts/zc-christ-hebrews-10-11.py

Source data used:
- data/interlinear/hebrews.json
- data/translation/draft/mediating/hebrews.json
- data/commentary/mkt-christ/hebrews.json (existing entries for chs 1–9, 12–13)

Key decisions in this range:
- 10:1 law as shadow: "A shadow:" — skia is the explicit Hebrews term; the good things = Christ's work
- 10:5-7 Ps 40 body-offering: "A fulfillment:" — the Son's words at incarnation fulfilling Ps 40
- 10:10 once for all sanctification: "A direct revelation:" — the completed sanctification
- 10:19-22 access to holiest: "A direct revelation:" — the opened way as present reality
- 10:37-38 Hab 2 + faith: "A fulfillment:" — the coming-one of Habakkuk = Christ
- 11:2 commendation by faith: "A revelation of God:" — unity of faith-principle across both covenants
- 11:17-19 Aqedah: "A type:" — Abraham offering Isaac as type of the Father offering the Son
- 11:26 Moses' reproach of Christ: "A shadow:" — Moses participating in the messianic reproach
- 11:35 better resurrection: "A direct revelation:" — Christ's resurrection as the definitive better
- 11:39-40 not perfected without us: "A direct revelation:" — the communal eschatology
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HEBREWS = {
  "10": {
    "1": '<p>A shadow: the law contains only a shadow (<em>skian</em>) of the good things that are coming, not the true form of those realities. Hebrews here names its own hermeneutical principle: the Levitical system is the shadow that the body of Christ casts backward into the old covenant. The shadow is real and instructive — it is the shape of what is coming — but it is not the thing itself. Christ is the substance that the annual sacrifices could only outline. The repetition of sacrifice was itself the evidence of the shadow-nature: a shadow must keep being redrawn because it is not the reality.</p>',
    "2": '<p>A revelation of God: if the sacrifices had achieved genuine cleansing, they would have ceased — the worshippers would have had no more consciousness of sin. The logic discloses what full atonement must accomplish: not the covering of sin pending further offerings, but the complete removal of guilt such that the conscience is permanently clear. This is what Christ achieves (v. 22): the heart sprinkled clean and the conscience no longer accusing. The repetition of sacrifice was a perpetual announcement that full atonement had not yet come.</p>',
    "3": '<p>A shadow: the annual reminder (<em>anamnēsis</em>) of sins at Yom Kippur is the negative shadow — it announces what is needed rather than providing it. The Day of Atonement was not a celebration of accomplished forgiveness but a yearly acknowledgment of ongoing guilt. Christ is the antitype in which sins are not reminded but removed and remembered no more (v. 17): his sacrifice is the anti-memory, the permanent removal that makes the annual reminder obsolete.</p>',
    "4": '<p>A revelation of God: the impossibility of animal blood removing sins discloses a necessary truth about what effective atonement requires. If bull and goat blood cannot remove sin, then the one whose blood can must be categorically different — not another creature offering, but the Son offering himself. The impossibility of the shadow is the inverse image of the necessity of the Incarnation: only the blood of one who is both truly divine and truly human can accomplish what the Levitical system announced but could not achieve.</p>',
    "5": '<p>A fulfillment: "Sacrifice and offering you did not desire, but a body you have prepared for me." The Son speaks these words at his entry into the world, applying Psalm 40:6-8 to himself. The body prepared for the Son is the instrument of the will-doing that replaces and fulfills what the animal sacrifices only anticipated. The incarnation is the fulfillment of the Psalm\'s declaration: the one who comes to do God\'s will is the Son, the will he does is his obedient self-offering, and the body he does it in is the one God prepared for him at Bethlehem.</p>',
    "6": '<p>A fulfillment: the continuation of the Psalm 40 citation — God\'s declared non-pleasure in burnt offerings even as they operated within his covenant. The prophetic tradition consistently signals (Isa 1:11; Jer 6:20; Amos 5:21) that the sacrifices were never the ultimate aim but pointed beyond themselves. What God desires is the obedient will-doing of the Son. The citation reveals that the old covenant\'s own prophetic voice anticipated the replacement of the sacrificial apparatus with the one whom the apparatus foreshadowed.</p>',
    "7": '<p>A fulfillment: "Behold, I have come to do your will, O God, as it is written of me in the scroll of the book." The Son\'s entry into the world as the fulfillment of Ps 40:8 — the words placed on his lips at incarnation. This is the theological key to Hebrews\' doctrine of atonement: not an unwilling victim but the Son whose entire being is constituted by doing the Father\'s will. The atonement works because the Son willed it, submitted to it, and accomplished it as the eternally obedient Son in the form of a servant.</p>',
    "8": '<p>A fulfillment: the Psalm citation is summarized and its conclusion drawn — what God neither desired nor took pleasure in (despite the Mosaic ordinance commanding them) was the first covenant order of sacrifices. The double negation emphasizes that the old order was always provisional. The summary prepares for the interpretive conclusion: the author is not reporting a Mosaic failure but revealing that even within the old covenant God was pointing past it toward the one whose obedient will-doing was always the goal.</p>',
    "9": '<p>A direct revelation: Christ removes the first covenant order in order to establish the second. The abolition of the Levitical system is not historical accident or Roman-era disruption but a theological consequence of the Son\'s coming: the shadow is removed when the substance arrives. The "second" — Christ\'s will-doing, his body-offering, his eternal high priesthood — is not an improvisation but what the first always pointed toward. The removal of the first is the revelation that the first was designed to be removed when its purpose was accomplished.</p>',
    "10": '<p>A direct revelation: we have been sanctified through the offering of the body of Jesus Christ once for all. The sanctification accomplished by Christ\'s body-offering is a completed act (aorist-perfect: we have been sanctified) with permanent effect. The "once for all" (<em>ephapax</em>) is the theological key: it cannot be supplemented, repeated, or improved. Those who are in Christ are fully and permanently holy before God because of what Christ did — not partially holy pending further sacrifice or repeated ritual.</p>',
    "11": '<p>A shadow: every Levitical priest stands day after day in service — the standing posture reveals what the sitting of Christ (v. 12) means. No priest ever sat in the sanctuary because the work was never done; the standing was the posture of ongoing, incomplete service. The repeated same sacrifices that could never take away sins are the shadow by negative contrast: they announce by their inadequacy and perpetuity that something qualitatively different was required. The standing priest points to the sitting Christ.</p>',
    "12": '<p>A direct revelation: Christ, having offered one sacrifice for sins for all time, sat down at the right hand of God. The sitting posture is the posture of completed work — the priestly work is finished; no further offering is needed or possible. The right-hand session (Ps 110:1) is the evidence of divine acceptance: the Father has received the Son\'s sacrifice and enthroned him. The once-for-all sacrifice and the session are inseparable: the sacrifice is complete because the priest has sat down.</p>',
    "13": '<p>A fulfillment: "until his enemies are made a footstool for his feet" (Ps 110:1). The session involves active waiting for the eschatological subjugation of all enemies. The Christ who has completed atonement and is enthroned is now in the "until" phase of his reign — the kingdom is inaugurated but not yet consummated, the enemies are defeated in principle but not yet visibly subjected. The parousia is the moment of the enemies\' footstool-making, the completion of what the resurrection-exaltation began.</p>',
    "14": '<p>A direct revelation: by a single offering he has brought to completion for all time those who are being made holy. The paradox of complete-in-Christ but still-being-made-holy-in-experience is the key to understanding sanctification: the atonement is not partial or provisional. Those in Christ have been brought to completion (<em>teteleiōken</em>, perfect tense: it stands completed) by the one offering. The present progressive "being sanctified" describes the application process, not the achievement — the achievement is already perfect and permanent.</p>',
    "15": '<p>A direct revelation: the Holy Spirit also bears witness to us. The Trinitarian structure of the community\'s assurance: the Son achieved the atonement; the Father made the new covenant promise; the Spirit testifies to both. The community\'s confidence rests not on their subjective experience but on the Spirit-attested word — the Spirit who spoke through Jeremiah now speaks through the new covenant fulfillment, bearing witness to the forgiveness Christ has secured.</p>',
    "16": '<p>A fulfillment: "I will put my laws on their hearts and write them on their minds" (Jer 31:33). The new covenant promise is fulfilled in Christ: the law internalized by the Spirit is the eschatological gift that the old covenant announced but could not achieve. What stone tablets and animal sacrifices could not effect — inner transformation, willing obedience from renewed hearts — is given through the Spirit purchased by Christ\'s blood. The new covenant is not merely better legislation but a new creation of the person from within.</p>',
    "17": '<p>A fulfillment: "I will remember their sins and their lawless deeds no more" (Jer 31:34). The divine not-remembering of sins is the final element of the new covenant\'s fulfillment. This is not amnesia but the consequence of genuine atonement: the debt has been paid, the record cleared, the guilt removed. Christ\'s sacrifice is the ground of this divine forgetting — not that God ignores sin, but that the sin has been fully dealt with by the one who bore it. The community stands before God with a permanently clear record.</p>',
    "18": '<p>A direct revelation: where there is forgiveness of sins, there is no longer any offering for sin. The logical conclusion of the atonement is the permanent obsolescence of the sacrificial system. If sins are genuinely forgiven — not merely deferred or covered — no further sacrifice is needed or can be offered. This reveals the completeness of Christ\'s work: the entire Levitical apparatus is not paused but ended, not by historical contingency but by theological consequence. The cross is the reason the temple\'s destruction matters.</p>',
    "19": '<p>A direct revelation: we have confidence (<em>parrēsia</em>) to enter the holy places by the blood of Jesus. The bold access to the Father through Christ\'s opened way is the present reality of the community — not something reserved for the high priest on Yom Kippur or for the eschatological future, but available now to every believer. The confidence is not presumption but the appropriate response to the completed atonement: to approach timidly what Christ has opened boldly would be to dishonor his work.</p>',
    "20": '<p>A direct revelation: Christ opened for us a new and living way through the curtain, that is, through his flesh. The identification of the torn curtain with Christ\'s body is the key interpretive move: his death (the tearing of his flesh) is simultaneously the opening of access to the Father\'s presence. The curtain separated humanity from the divine holiness; Christ\'s body-sacrifice is the curtain-tearing that renders that separation obsolete. The way is "living" because Christ is alive and his ongoing intercession sustains the open access for those who come through him.</p>',
    "21": '<p>A direct revelation: we have a great high priest over the house of God. The enthroned Son functions as high priest not from the earthly shadow-sanctuary but from the heavenly reality, interceding continually for the community that is itself the house of God. The "great" priest does not merely exceed the Levitical high priests in degree but surpasses them in kind: they served in the earthly copy; he serves in the heavenly original; they offered animals; he offered himself; they entered once a year; he entered permanently.</p>',
    "22": '<p>A direct revelation: let us draw near with sincere hearts in full assurance of faith, with hearts sprinkled clean from an evil conscience and bodies washed with pure water. The invitation to draw near — which the Levitical curtain had barred for all but the high priest — is now extended to the whole covenant community. The conditions described (inner cleansing, outer identification) are the new covenant realities Christ secured: the conscience purified by his blood and the body marked by baptism into his death. The drawing-near is the community\'s participation in what Christ has achieved.</p>',
    "23": '<p>A direct revelation: let us hold firmly to the confession of our hope without wavering, for he who promised is faithful. The ground of the community\'s holding fast is not their own grip on the hope but the faithfulness of the one who promised — the same divine faithfulness that kept every covenant promise across the centuries and that is finally and definitively expressed in Christ\'s resurrection. The confession of hope is hope in Christ\'s return and the full realization of everything his atonement secured.</p>',
    "24": '<p>A revelation of God: let us consider how to stir one another on to love and good works. The horizontal ethic of mutual encouragement flows from the vertical reality of the atonement: because Christ has made the community one body before God, members share responsibility for one another\'s perseverance. Love and good works are not the ground of acceptance but the evidence of it — the life that the Spirit produces in those who have genuinely drawn near to God through Christ.</p>',
    "25": '<p>A direct revelation: not neglecting to meet together, and all the more as you see the Day drawing near. The Day of the Lord — Christ\'s return — is the eschatological horizon that gives urgency to the community\'s assembly. The assembly is the earthly anticipation of the great heavenly assembly (12:22-24) that the return will complete. The encouragement exchanged in the assembly is the community\'s participation in what the enthroned Son is already doing — sustaining the faithful by his intercession through the waiting period before the Day.</p>',
    "26": '<p>A revelation of God: if we sin deliberately after receiving the knowledge of the truth, there no longer remains a sacrifice for sins. The warning presupposes the fullness of what Christ has achieved: precisely because the sacrifice is once-for-all and complete, there is no second sacrifice for those who deliberately abandon it. The severity is proportional to the greatness of the provision: the richer the grace, the more catastrophic the deliberate rejection. This is not addressed to involuntary sin but to the willful apostasy of those who turn their backs on Christ knowing what they are rejecting.</p>',
    "27": '<p>A revelation of God: a terrifying expectation of judgment and a raging fire that will consume the adversaries of God. The consuming fire (Isa 26:11) is the character of divine holiness encountering undealt-with sin. What Christ absorbed in his death as the judgment-bearing sacrifice is what awaits those who reject him: the fire that should have consumed them falls instead on the one who had no sin, and those who reject him remain in the path of it. The judgment is real because the holiness is real.</p>',
    "28": '<p>A shadow: anyone who rejected the law of Moses died without mercy on the evidence of two or three witnesses. The Mosaic capital penalty for covenant-breaking is the shadow of the final judgment\'s logic: if the shadow of the first covenant brought death without mercy, how much more the reality of the new? The argument is a fortiori — from the lesser (Mosaic penalty) to the greater (eschatological judgment) — and it is the same argument used throughout Hebrews to establish Christ\'s supremacy.</p>',
    "29": '<p>A direct revelation: how much worse punishment will be deserved by the one who has trampled underfoot the Son of God, treated his covenant blood as common, and outraged the Spirit of grace? The Trinitarian structure of the offense reveals the Trinitarian structure of the gospel: the Son is the mediator, his blood is the new covenant blood, the Spirit is the Spirit of grace through whom the gospel is received. To trample, treat-as-common, and outrage these three is to reject the entire economy of salvation. The punishment is incomparably greater because the provision was incomparably greater.</p>',
    "30": '<p>A revelation of God: "Vengeance is mine; I will repay" and "The Lord will judge his people" (Deut 32:35-36). The divine justice that judged Israel in the wilderness is the same justice that operates in the new covenant community. God who was faithful to judge his own people under Moses is faithful to judge those who betray the new covenant. This is not arbitrary wrath but the judicial faithfulness of the covenant God to his own standards — the same faithfulness that grounds both the promises and the warnings.</p>',
    "31": '<p>A revelation of God: it is a terrifying thing to fall into the hands of the living God. The living God — not an idol or an abstraction but the personally active, covenant-making, resurrection-working God — is the one before whom apostates will stand. The terror is not of an anonymous force but of the Father who provided the Son, whose provision has been knowingly rejected. The one who gives life has the power to withhold it; the one whose hands sustain all creation can also judge all creation.</p>',
    "32": '<p>A direct revelation: recall the earlier days when, after you were enlightened, you endured a hard struggle. The "enlightenment" (<em>phōtisthentes</em>) refers to conversion and baptism — entry into the new covenant community — and the persecution that followed was the expected response of the world to those who belong to Christ. The community\'s past endurance is evidence of genuine faith and a pattern for present faithfulness: those who endured then can endure now, because the same Christ who sustained them then sustains them now.</p>',
    "33": '<p>A theme: the theme of the reproach of Christ that runs through Hebrews (11:26; 13:13) surfaces in the community\'s own experience — their public shaming and affliction are their participation in the same rejection that Christ himself received. To bear reproach alongside the people of God is to be identified with the one who bore reproach for them. The community\'s suffering is not merely unfortunate circumstance but the shape of their solidarity with the crucified Messiah.</p>',
    "34": '<p>A direct revelation: you joyfully accepted the plundering of your property, knowing that you yourselves had a better possession and an abiding one. The community\'s joy in earthly loss reveals the eschatological orientation that faith in Christ produces: the better and enduring possession is the heavenly inheritance — the city with foundations (11:10), the unshakeable kingdom (12:28) — that Christ has secured and that no earthly confiscation can touch. To lose what is temporary while holding what is permanent is the logic of resurrection faith.</p>',
    "35": '<p>A direct revelation: do not throw away your confidence, which carries a great reward. The confidence (<em>parrēsia</em>) is the bold access to the Father that Christ\'s atonement creates — the posture of approaching God as one who has been welcomed, not tentatively or anxiously but with the assurance of those whose guilt has been removed. The reward (<em>misthapodosia</em>) is the inheritance, the rest, the city that Abraham saw in faith — what the enduring community will receive when the Day comes.</p>',
    "36": '<p>A revelation of God: you need endurance, so that when you have done the will of God you may receive what was promised. The will of God here is not the moral law alone but the specifically covenantal will-doing that Christ modeled: faithful endurance through suffering toward the resurrection-reward. The community follows Christ in the same pattern — faith-obedience through trials that led him to the session at the right hand. The promise is certain; what is required is endurance in the path that Christ already walked.</p>',
    "37": '<p>A fulfillment: "He who is coming will come and will not delay" (Hab 2:3-4). The "coming one" of Habakkuk — the vision awaiting its appointed time — is fulfilled in Christ\'s first advent and anticipated in his second. The same Habakkuk-logic applies to the community waiting for the parousia: the vision (Christ\'s return) awaits its time, will certainly come, and the righteous are those who live by faith through the waiting rather than shrinking back. The coming of Christ is the answer to the prophet\'s watch.</p>',
    "38": '<p>A fulfillment: "My righteous one shall live by faith, and if he shrinks back, my soul takes no pleasure in him" (Hab 2:4). The text is applied both to Christ (the supreme righteous one who lived by faith, Heb 12:2) and to the community that follows him. Christ endured to the end; those who belong to him are called to the same enduring faith. The shrinking back (<em>hypostellē</em>) is the abandonment of the bold access and the confession of hope — the opposite of what Christ modeled in his faithful endurance to the cross.</p>',
    "39": '<p>A direct revelation: we do not belong to those who shrink back and are destroyed, but to those who have faith and so preserve their souls. The positive assurance that closes the warning section: the author identifies himself and the community with the faithful, not the apostates. The preservation of the soul is not the fruit of heroic effort but of the faith that trusts the completed work of Christ and endures in hope toward the Day. The community\'s identity is established by this trust, not undermined by the warnings that address its opposite.</p>'
  },
  "11": {
    "1": '<p>A direct revelation: faith is the assurance of things hoped for, the proof of things not seen. The definition locates faith within the economy of divine revelation: what faith grasps is not imagination but disclosed reality — the things hoped for are real because God has revealed them in Christ; the things not seen are the eschatological realities that the Spirit witnesses to the community. The definition situates every believer in the same position as the OT cloud of witnesses: seeing the promised-but-not-yet-fully-realized, and holding to it as the most real thing in their world.</p>',
    "2": '<p>A revelation of God: by faith the people of old received their commendation. The OT saints were not commended by works-righteousness or covenant-membership alone but by faith — the same principle that operates in the new covenant. This reveals the unity of the way of salvation across both testaments: Abraham, Abel, Noah, and all the elders were right with God by trusting his word, just as the community of Christ is right with God by trusting the word of the Son. The faith-principle is not new covenant innovation but the constant of covenant relationship.</p>',
    "3": '<p>A revelation of God: by faith we understand that the universe was formed by God\'s word, so that what is seen was not made from visible things. Creation-faith is the foundation of all other faith: God who creates from nothing can fulfill promises that seem impossible. The invisible word produces the visible world — the paradigm of faith\'s operation. In Christ, the same pattern applies: from the nothing of the sealed tomb, God\'s word produces the resurrection. Faith in the creator God and faith in the resurrection God are the same trust in the same power.</p>',
    "4": '<p>A shadow: Abel\'s faith-offering that was acceptable to God is the first shadow of the one true acceptable offering. Abel brought the firstborn of his flock in faith; God received it. Christ is the firstborn of all creation (Col 1:15) who offers himself as the definitively acceptable sacrifice. Abel\'s blood cried from the ground for justice; Christ\'s blood speaks the better word (12:24) — not vengeance but forgiveness. The shadow-structure: the acceptable-faith offering points to the once-for-all offering that is accepted not merely for the offerer but for all who share the faith.</p>',
    "5": '<p>A shadow: Enoch was taken from this life so that he did not experience death — the pattern: faith, pleasing God, escaping death. This is the OT shadow of what Christ achieves definitively: by his obedient death he destroys the power of death for all who are in him (2:14). Enoch bypassed death as an individual exception; Christ conquers death as the head of a new humanity. The translation of Enoch is the shadow; the resurrection of Christ and the eschatological transformation of the community at his return (1 Cor 15:52) is the fulfillment.</p>',
    "6": '<p>A revelation of God: without faith it is impossible to please God, because anyone who comes to him must believe that he exists and that he rewards those who seek him. The structure of relationship to God is disclosed as inherently relational (to a God who is, who sees, who responds) and inherently eschatological (seeking him as the rewarder). This is not works-based seeking but faith-seeking: trusting that the unseen God is real and that his promised reward will come. Christ is the supreme expression of the rewarder: in him, the one who believes receives eternal life (John 3:16).</p>',
    "7": '<p>A shadow: Noah, warned about unseen judgment, built an ark in reverent faith and saved his household, becoming heir of righteousness by faith. The pattern: divine warning about coming judgment, faith-obedience that prepares a means of salvation, and the salvation of those who enter. The antitype: Christ is warned by the Spirit of coming judgment and, knowing it as the Son, provides by his death the salvation-vessel into which faith enters. Baptism connects the community to the Noah typology (1 Pet 3:20-21): those who are in Christ are in the ark; judgment passes over them.</p>',
    "8": '<p>A shadow: by faith Abraham obeyed when he was called to go to a place he would later receive as his inheritance, not knowing where he was going. Abraham\'s faith-obedience to a call without full disclosure of the destination is the shadow of Christian discipleship: called, baptized, following, not yet seeing the city but trusting the one who called. The father of faith models the pattern of new covenant life — stepping forward on the word of God without the ability to verify the destination by sight. The community of Christ follows the same path.</p>',
    "9": '<p>A theme: by faith Abraham lived in the promised land as a stranger in a foreign country, living in tents, as did Isaac and Jacob. The theme of sojourning — possessing the promise while living as a foreigner — runs from Abraham through the OT community to the new covenant community (1 Pet 2:11). The promised land was never the final home; the heavenly country was (v. 16). Christ is the one in whom the final homeland is secured: he has gone ahead (John 14:3) and prepared a place, and the community lives in the present world as strangers looking toward it.</p>',
    "10": '<p>A shadow: Abraham was looking for the city with foundations, whose architect and builder is God. Abraham\'s forward-looking faith toward the eternal city is the OT shadow of the eschatological reality Christ inaugurates. The city with foundations (Rev 21:10-14) is the new Jerusalem that descends from heaven — built not by human hands but by the God who builds through Christ\'s redemption. Abraham saw its outline from afar; the community sees the architect\'s face in Christ and holds the promise of the city more clearly than Abraham could from his tent.</p>',
    "11": '<p>A revelation of God: by faith even Sarah received ability to conceive because she considered him faithful who had promised. The character of the promising God is disclosed: he gives life to the barren, ability to the unable, fulfillment to the apparently-broken promise. The same God raises the dead (v. 19), fulfills covenants against biological impossibility, and raises Christ. The pattern of impossible-fulfilled-by-divine-faithfulness is the shape of all redemptive history, culminating in the resurrection of the crucified Son.</p>',
    "12": '<p>A revelation of God: from one man, as good as dead, came descendants as numerous as the stars of the sky and the sand on the seashore. The multiplication from the as-good-as-dead (<em>nenekrōmenou</em>) Abraham reveals the resurrection-pattern: from death and deadness God alone produces an abundance of life. In Christ, from the one who died and was raised, comes the innumerable community of faith from all nations (Rev 7:9). The logic of Abraham\'s biological resurrection is the logic of the community\'s eschatological resurrection in the Son.</p>',
    "13": '<p>A direct revelation: all these died in faith not having received the things promised; they only saw and greeted them from afar. The OT faithful died without receiving the fullness of the promise — it remained eschatologically ahead of them. This is Hebrews\' key to reading both testaments: the OT community held the promise in faith-sight; the NT community holds the fulfillment in Christ, but still awaits the final realization (v. 40). Both communities are faith-communities in the sense of holding what is real but not yet fully visible — the former looking forward, the latter looking both back (to the cross) and forward (to the parousia).</p>',
    "14": '<p>A theme: people who say such things show they are looking for a country of their own. The OT pilgrims\' self-description as strangers and foreigners is their confession that this world is not their final country. The theme of the sought-homeland runs through the entire biblical narrative: from Eden to the city with foundations, God\'s people are always moving toward a country they cannot yet see. The community of Christ lives in the same orientation — the new Jerusalem (Rev 21:2) is their homeland, and Christ who has already entered it (9:24) is their forerunner.</p>',
    "15": '<p>A revelation of God: if they had been thinking of the country they left, they would have had opportunity to return. The OT saints could have returned to Ur, to Egypt, to earthly security — but they chose the forward-looking faith instead. Their choice discloses the structure of faith: it is not nostalgia for the pre-faith life but trust in the promised future. The community of Christ similarly has opportunities to "return" to pre-conversion identities and securities, but the faith that saw the heavenly country makes the return impossible without abandoning what was seen.</p>',
    "16": '<p>A direct revelation: they were longing for a better country — a heavenly one. Therefore God is not ashamed to be called their God, for he has prepared a city for them. The OT faithful\'s longing for the heavenly country is the explicit disclosure that the entire OT narrative was always oriented beyond the earthly promised land. God is not ashamed to be called their God because he has actually prepared the city — the new Jerusalem (Rev 21:10) — through Christ\'s redemption. The God of Abraham, Isaac, and Jacob is the God who raised Jesus from the dead (Matt 22:31-32), validating this heavenly hope.</p>',
    "17": '<p>A type: by faith Abraham, when he was tested, offered up Isaac — he who had received the promises was in the act of offering his only son. The Aqedah is the supremely explicit OT type of the Father\'s offering of the Son: Abraham\'s willingness to give the beloved only son, the divine provision of a substitute (the ram in the thicket), and the receiving back correspond to the Father giving the Son, the Son\'s substitutionary death on behalf of the guilty, and his resurrection. The type preserves the structure of the atoning act at its deepest level — love that gives the uniquely beloved.</p>',
    "18": '<p>A type: "It is through Isaac that your offspring will be reckoned" — the divine word that made Isaac the vessel of the covenant promise is the type of the specificity of the covenant in Christ. The promise comes through the one designated by God, not through human logic or natural descent. As the promise came through the "impossible" Isaac born to the barren and aged, it comes through the crucified and risen Christ — the one whom death should have ended but whom God raised (Gal 3:16). The type preserves the pattern of divine specificity against natural impossibility.</p>',
    "19": '<p>A type: Abraham reasoned that God could raise the dead, and so in a manner of speaking (<em>en parabolē</em>) he did receive Isaac back. The Aqedah is the OT parable of resurrection: Abraham\'s trust that God could raise is the shadow of what actually happened in Christ\'s literal resurrection. Isaac "received back" from virtual death is the figure whose literal fulfillment is the empty tomb. The faith that trusts a God who raises the dead finds its ultimate validation in the resurrection of the Son, and those who share Abraham\'s resurrection-reasoning share his justification (Rom 4:24-25).</p>',
    "20": '<p>A theme: by faith Isaac blessed Jacob and Esau in regard to their future. Isaac\'s faith-blessing looks beyond what the eye sees to what God\'s promise will make. The theme of the covenant-blessing transmitted through the chosen line anticipates the Christological reality: the blessing of Abraham (Gal 3:14) comes through the seed who is Christ. Isaac\'s faith-act participates in the forward movement of the covenant promise through unexpected channels — Jacob over Esau — the pattern of divine election running contrary to natural expectation that culminates in the crucified Messiah.</p>',
    "21": '<p>A theme: by faith Jacob, when he was dying, blessed each of Joseph\'s sons and worshipped as he leaned on his staff. Jacob\'s faith-blessing at death — crossing his hands to place the greater blessing on the younger (Gen 48:14) — continues the pattern of God\'s surprising election running contrary to human convention. The blessing flows through the unexpected one, as it does ultimately in Christ: the stone the builders rejected (Ps 118:22) becomes the cornerstone; the firstborn from the dead who was crucified in apparent weakness inherits all things (1:2; Col 1:18).</p>',
    "22": '<p>A shadow: by faith Joseph, when he was dying, spoke of the exodus of the Israelites and gave instructions about his bones. Joseph\'s dying faith-instruction points two directions: his bones were to participate in the great deliverance (Exod 13:19), and his faith anticipated the exodus as the paradigmatic act of divine rescue. The exodus itself is the shadow of the greater exodus Christ accomplishes (Luke 9:31) — delivering his people through the waters of death into the promised inheritance. Joseph\'s bones-instruction is a faith-confession that the story is not over at death and that God\'s deliverance is bodily and communal.</p>',
    "23": '<p>A shadow: by faith Moses\' parents hid him for three months, not fearing the king\'s edict, because they saw he was a fine child. The faith of Moses\' parents — seeing his worth against the royal death-decree — is the shadow of the faith that recognizes the worth of Christ when the world seeks to destroy him. Pharaoh\'s edict to kill Hebrew infant boys corresponds to Herod\'s massacre of the innocents (Matt 2:16-18). The preservation of the infant Moses against the killing-king anticipates the preservation of Jesus through Egypt and his emergence as the deliverer.</p>',
    "24": '<p>A shadow: by faith Moses, when he had grown up, refused to be known as the son of Pharaoh\'s daughter. Moses\' refusal of Egyptian royal identity in solidarity with the oppressed people is the OT shadow of the Incarnation: the Son of God who did not count equality with God a thing to be grasped but took on the form of a servant (Phil 2:6-7). The voluntary identity-change — from security and status to solidarity with the suffering — is the shape of both Moses\' faith-choice and the Son\'s redemptive self-emptying. The shadow is real; the antitype is immeasurably greater.</p>',
    "25": '<p>A shadow: Moses chose to be mistreated with the people of God rather than enjoy the fleeting pleasures of sin. The choice of suffering-with over comfort-for-self is the shadow of the cross. Christ, for the joy set before him, endured the cross, scorning its shame (12:2). Moses, for the reward (v. 26), chose the reproach. The same eschatological orientation — future reward over present pleasure — structures both the shadow (Moses\' faith-choice) and the reality (Christ\'s cross-bearing). The community of Christ is called into the same pattern.</p>',
    "26": '<p>A shadow: Moses regarded the reproach suffered for the sake of Christ as greater wealth than the treasures of Egypt, because he was looking to the reward. Moses participates in the messianic reproach across the centuries — not because he knew Christ as the community does, but because the reproach of God\'s people (which Moses took on by identifying with Israel) is structurally the same as the reproach of the Messiah. The community that bears the reproach of Christ (13:13) enters the same pattern: what Moses began in shadow, the community enacts in the light of the disclosed Messiah.</p>',
    "27": '<p>A revelation of God: by faith Moses left Egypt, not fearing the king\'s anger, because he saw him who is invisible. Moses\' ability to endure is grounded in seeing the invisible God — the same God who is disclosed definitively in Christ (1:3: the exact imprint of God\'s nature). The community of Christ similarly sees the invisible (the enthroned Son, the heavenly sanctuary) by faith and is enabled to endure what the visible world threatens. Moses\' vision of the invisible God is the OT shadow of the community\'s vision of Christ by faith and Spirit.</p>',
    "28": '<p>A type: by faith Moses kept the Passover and the application of blood, so that the destroyer of the firstborn would not touch them. The Passover blood applied to the doorposts — protecting the Israelite firstborn from the destroying angel — is the structural type of Christ\'s blood applied to the believer. The destroyer passes over those who are covered; the divine judgment of wrath passes over those who are in Christ, covered by his atoning blood. Paul makes the type explicit (1 Cor 5:7); John names the reality (John 1:29). The Passover is the oldest and most structurally precise type of the cross.</p>',
    "29": '<p>A shadow: by faith the people passed through the Red Sea as on dry land, but when the Egyptians tried they were drowned. The Red Sea crossing is the shadow of baptism (1 Cor 10:2) — the community passing through the waters of death into the new life beyond. The water that delivers God\'s people destroys their pursuers. Christ\'s death and resurrection are the reality of which the sea-crossing was the figure: he went through the waters of death and emerged alive, taking his people through with him. Those who are in Christ have already passed through the waters of judgment.</p>',
    "30": '<p>A revelation of God: by faith the walls of Jericho fell after the army had marched around them for seven days. The walls-collapse demonstrates God\'s pattern of victory through non-conventional means — marching and trumpets rather than siege weapons. The enemy\'s strongholds fall not by human technique but by faith-obedience to God\'s instruction. The community of Christ trusts the same pattern: the strongholds of sin and death have been demolished by Christ\'s cross — the apparent foolishness of God that is wiser than human wisdom (1 Cor 1:25). The victory is God\'s; the community marches by faith.</p>',
    "31": '<p>A shadow: by faith Rahab the prostitute did not perish with those who were disobedient, because she welcomed the spies in peace. Rahab\'s faith — expressed in her reception of the Israelite messengers and the application of the scarlet cord in her window — is the shadow of the faith that receives Christ\'s messengers and is protected by his blood. The scarlet thread marking the house of the saved is a long-noted prefiguration of the blood that marks off those who are covered from those who are not. The Gentile outsider included in the people of God by faith anticipates the new covenant inclusion of all nations in Christ.</p>',
    "32": '<p>A revelation of God: what more shall I say? Time would fail me to tell of Gideon, Barak, Samson, Jephthah, David, Samuel, and the prophets. The compression acknowledges the abundance of faith-witnesses without exhausting them. The figures named — judges, king, prophets — span the entire era of Israel\'s covenant history, showing that faith-in-God was the constant through every institutional form. In Christ, all these institutional forms find their fulfillment: judge who delivers, king who reigns, prophet who speaks — all offices he holds and surpasses.</p>',
    "33": '<p>A revelation of God: through faith they conquered kingdoms, administered justice, gained what was promised, shut the mouths of lions. The catalog of faith-victories reveals the character of the God who responds to faith across the centuries: he delivers from kings, animals, and fire; he gives what he has promised; he establishes justice through his people. The Christ who is the same yesterday, today, and forever (13:8) is the one who worked these victories in the shadow-time and who now works the greater victory over sin and death in the fulfilled time.</p>',
    "34": '<p>A revelation of God: weakness was turned to strength, and armies of foreigners were routed. Weakness turned to strength is the resurrection pattern: the one who was weak enough to die on the cross was given the strength of indestructible life (7:16). The OT figures who experienced the weakness-to-strength reversal are the shadows of what Christ achieves definitively and what the community enters eschatologically: "when I am weak, then I am strong" (2 Cor 12:10) is the shape of new covenant existence.</p>',
    "35": '<p>A direct revelation: women received their dead raised to life again. There were others who were tortured, refusing release, so that they might rise to a better resurrection. The "better resurrection" toward which some OT faithful died without attaining is the resurrection that Christ\'s own resurrection inaugurates and guarantees. The temporary restorations (1 Kgs 17:22; 2 Kgs 4:35) were gracious but provisional — the dead raised returned to die again. The better resurrection is the permanent, eschatological raising that is now secure in Christ the firstfruits (1 Cor 15:23), from which there is no second dying.</p>',
    "36": '<p>A theme: some faced jeers and flogging, chains and imprisonment. The suffering of God\'s faithful witnesses is the continuous theme of covenant history — the prophets mocked and imprisoned (Jer 37-38; 1 Kgs 22:27) are the cloud that surrounds the community. Christ is the prophet above all others who endured jeering, flogging, and imprisonment before his execution. The community that bears the same reproach (13:13) enters the same fellowship with the one who went before them through the same suffering to the same glory.</p>',
    "37": '<p>A theme: they were stoned, sawn in two, killed by the sword; they went about in sheepskins and goatskins, destitute, afflicted, mistreated. The extreme suffering and destitution of the faithful witnesses finds its ultimate expression in the cross. The one who had no place to lay his head, who was stripped and executed between criminals, is the final and fullest expression of the faithful-sufferer pattern. The tradition of Isaiah sawn in two, Jeremiah stoned, John the Baptist killed by sword — all point toward the one whose suffering was not merely in the same pattern but was the pattern\'s reason and goal.</p>',
    "38": '<p>A revelation of God: the world was not worthy of them — they wandered in deserts, mountains, and caves. The divine counter-evaluation stands against the world\'s verdict: those whom the world expelled and deemed unworthy were the ones God valued as the world was not worthy to contain. In Christ, the same divine counter-judgment operates definitively: the one whom the world crucified as worthy only of death, God declared worthy of all honor (Rev 5:12) by raising him and seating him at the right hand. The resurrection is God\'s public repudiation of the world\'s verdict on his Son.</p>',
    "39": '<p>A direct revelation: these were all commended for their faith, yet none of them received what was promised. The OT saints were commended — God testified to their faith — but they died without the fulfillment. The "what was promised" is the whole of the new covenant reality: the definitive atonement, the indwelling Spirit, the opened sanctuary, the city with foundations. All of this awaited Christ\'s coming. Their faith was genuine and their commendation real; the promise was simply not yet accomplished. They held the forward end of the promise; the community of Christ holds the backward and forward ends together.</p>',
    "40": '<p>A direct revelation: God had planned something better for us so that apart from us they should not be made perfect. The "something better" is the realized eschatology of the new covenant — Christ\'s atonement, resurrection, and the Spirit — which the OT faithful glimpsed but could not participate in until the community of Christ was also gathered. The perfection is communal and final: Abel, Noah, Abraham, Moses, Rahab, and all the faithful of every age are perfected together at the parousia in Christ. The whole people of faith, from the first to the last, enters the completion as one body — which is why the community\'s perseverance to the end matters for the whole story of salvation.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'hebrews')
    merge_comm(existing, HEBREWS)
    save_comm('mkt-christ', 'hebrews', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Hebrews mkt-christ: {len(existing)} chapters, {total} verses written.')

if __name__ == '__main__':
    main()
